# ──────────────────────────────────────────────────────────────────────────────
# 時辰對應（Shichen — Two-hour periods）
# ──────────────────────────────────────────────────────────────────────────────

# 24小時制 → 地支索引（0=子）
def hour_to_branch_idx(hour: int) -> int:
    """Convert a 24-hour clock hour to the earthly branch index (0 = 子).

    子時：23:00–00:59 → 0
    丑時：01:00–02:59 → 1
    ...
    亥時：21:00–22:59 → 11
    """
    if hour == 23:
        return 0
    return (hour + 1) // 2

